import React, { useState, useEffect } from 'react';
import PropTypes from 'prop-types';
import recipeDetailsAPI from '../utils/requestsAPI';

function RecepeDetails({ match }) {
  const [item, setItem] = useState('');
  const [details, setDetails] = useState({});
  const [ingredients, setIngredients] = useState([]);
  const [measure, setMeasure] = useState([]);

  const filterIngredients = (key) => {
    const entriesIngredients = Object.entries(details).filter((e) => (
      e[0].includes(key) === true && e[1] !== null));
    const ingredientes = entriesIngredients.map((e) => e[1]);
    return ingredientes;
  };

  useEffect(() => {
    const request = async () => {
      const response = await recipeDetailsAPI[match.path](match.params.id);
      const firstItem = Object.keys(response)[0];
      setDetails(response[firstItem][0]);
      const saveItem = {
        '/meals/:id': () => setItem('Meal'),
        '/drinks/:id': () => setItem('Drink'),
      };
      saveItem[match.path]();
    };
    request();
    setIngredients(filterIngredients('strIngredient'));
    setMeasure(filterIngredients('strMeasure'));
  }, []);

  return (
    <div>
      <img data-testid="recipe-photo" src={ details[`str${item}Thumb`] } alt="imagem" />
      <h1 data-testid="recipe-title">{ details[`str${item}`] }</h1>
      <p data-testid="recipe-category">{ details.strCategory }</p>
      {
        item === 'Drink'
          && <p>{ details.strAlcoholic }</p>
      }
      {
        filterIngredients('strIngredient').map((e) => (
          <p key={ e }>{ e }</p>
        ))
      }
    </div>
  );
}

RecepeDetails.propTypes = {
  match: PropTypes.shape({
    path: PropTypes.string.isRequired,
    params: PropTypes.shape({
      id: PropTypes.string.isRequired,
    }).isRequired,
  }).isRequired };

export default RecepeDetails;
